export default function UseCaseFinder() {
  const [step, setStep] = useState<"industry" | "department" | "results">(
    "industry"
  );
  const [selectedIndustry, setSelectedIndustry] = useState<IndustryKey | null>(
    null
  );
  const [selectedDepartment, setSelectedDepartment] =
    useState<DepartmentKey | null>(null);

  const industries: IndustryKey[] = [
    "healthcare",
    "financial",
    "retail",
    "manufacturing",
    "education",
    "technology",
    "media",
    "professional",
  ];

  const departments: DepartmentKey[] = [
    "sales",
    "operations",
    "hr",
    "finance",
    "customer",
    "product",
  ];

  const handleIndustrySelect = (industry: IndustryKey) => {
    setSelectedIndustry(industry);
    setStep("department");
  };

  const handleDepartmentSelect = (department: DepartmentKey) => {
    setSelectedDepartment(department);
    setStep("results");
  };

  const getResults = (): UseCase[] => {
    if (!selectedIndustry || !selectedDepartment) return [];
    const key = `${selectedIndustry}-${selectedDepartment}`;
    return useCases[key] || [];
  };

  const results = getResults();

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty) {
      case "Easy":
        return "bg-green-100 text-green-800";
      case "Medium":
        return "bg-yellow-100 text-yellow-800";
      case "Hard":
        return "bg-red-100 text-red-800";
      default:
        return "bg-slate-100 text-slate-800";
    }
  };

  const getROIStars = (roi: string) => {
    switch (roi) {
      case "$":
        return "$";
      case "$$":
        return "$$";
      case "$$$":
        return "$$$";
      default:
        return "$";
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Breadcrumb */}
      <div className="bg-white border-b border-slate-200">
        <div className="max-w-6xl mx-auto px-6 py-4 text-sm text-slate-600">
          <span>Home</span> <span className="mx-2">/</span>
          <span>AI for Corporates</span> <span className="mx-2">/</span>
          <span>Use Case Finder</span>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-6 py-12">
        {/* Header */}
        <div className="mb-12">
          <h1 className="text-4xl font-bold text-slate-900 mb-2">
            AI Use Case Finder
          </h1>
          <p className="text-lg text-slate-600">
            Discover relevant AI use cases for your industry and department.
            Learn about implementation difficulty, ROI potential, and real-world
            examples.
          </p>
        </div>

        {/* Step 1: Industry Selection */}
        {step === "industry" && (
          <>
            <h2 className="text-2xl font-bold text-slate-900 mb-8">
              Step 1: Select Your Industry
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-12">
              {industries.map((industry) => (
                <button
                  key={industry}
                  onClick={() => handleIndustrySelect(industry)}
                  className="p-6 bg-white rounded-lg border border-slate-200 hover:border-slate-400 hover:shadow-md transition-all text-left"
                >
                  <h3 className="font-bold text-slate-900">
                    {industryLabels[industry]}
                  </h3>
                </button>
              ))}
            </div>
          </>
        )}

        {/* Step 2: Department Selection */}
        {step === "department" && selectedIndustry && (
          <>
            <div className="mb-6 flex items-center gap-4">
              <button
                onClick={() => {
                  setSelectedIndustry(null);
                  setStep("industry");
                }}
                className="text-slate-700 font-semibold underline hover:text-slate-900"
              >
                ← Change Industry
              </button>
              <span className="text-slate-600">
                {industryLabels[selectedIndustry]}
              </span>
            </div>
            <h2 className="text-2xl font-bold text-slate-900 mb-8">
              Step 2: Select Your Department
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-12">
              {departments.map((dept) => (
                <button
                  key={dept}
                  onClick={() => handleDepartmentSelect(dept)}
                  className="p-6 bg-white rounded-lg border border-slate-200 hover:border-slate-400 hover:shadow-md transition-all text-left"
                >
                  <h3 className="font-bold text-slate-900">
                    {departmentLabels[dept]}
                  </h3>
                </button>
              ))}
            </div>
          </>
        )}

        {/* Step 3: Results */}
        {step === "results" && selectedIndustry && selectedDepartment && (
          <>
            <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
              <div>
                <p className="text-slate-600 text-sm">Showing results for:</p>
                <p className="text-lg font-semibold text-slate-900">
                  {industryLabels[selectedIndustry]} •{" "}
                  {departmentLabels[selectedDepartment]}
                </p>
              </div>
              <button
                onClick={() => {
                  setSelectedIndustry(null);
                  setSelectedDepartment(null);
                  setStep("industry");
                }}
                className="px-4 py-2 bg-slate-700 text-white font-semibold rounded-lg hover:bg-slate-800 transition-colors"
              >
                Refine Results
              </button>
            </div>

            {results.length > 0 ? (
              <div className="space-y-6 mb-12">
                {results.map((useCase) => (
                  <div
                    key={useCase.id}
                    className="bg-white rounded-lg border border-slate-200 p-8 hover:shadow-md transition-shadow"
                  >
                    <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-4 mb-4">
                      <h3 className="text-xl font-bold text-slate-900">
                        {useCase.title}
                      </h3>
                      <div className="flex gap-2">
                        <span
                          className={`px-3 py-1 text-xs font-semibold rounded-full whitespace-nowrap ${getDifficultyColor(
                            useCase.difficulty
                          )}`}
                        >
                          {useCase.difficulty}
                        </span>
                        <div className="px-3 py-1 bg-amber-100 text-amber-800 text-xs font-semibold rounded-full whitespace-nowrap flex items-center gap-1">
                          <span>{getROIStars(useCase.roi)}</span>
                          <span
                            className="inline-block group cursor-help relative"
                            title={useCase.roiDescription}
                          >
                            {useCase.roiDescription}
                          </span>
                        </div>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-4">
                      <div>
                        <p className="text-xs font-semibold text-slate-600 uppercase mb-1">
                          Problem It Solves
                        </p>
                        <p className="text-slate-900">{useCase.problem}</p>
                      </div>
                      <div>
                        <p className="text-xs font-semibold text-slate-600 uppercase mb-1">
                          AI Technology
                        </p>
                        <p className="text-slate-900">{useCase.technology}</p>
                      </div>
                      <div>
                        <p className="text-xs font-semibold text-slate-600 uppercase mb-1">
                          Real Example
                        </p>
                        <p className="text-slate-900">{useCase.example}</p>
                      </div>
                      <div>
                        <p className="text-xs font-semibold text-slate-600 uppercase mb-1">
                          Time to Implement
                        </p>
                        <p className="text-slate-900">{useCase.timeToImplement}</p>
                      </div>
                    </div>

                    <a
                      href="#"
                      className="inline-block text-slate-700 font-semibold underline hover:text-slate-900"
                    >
                      Explore more articles →
                    </a>
                  </div>
                ))}
              </div>
            ) : (
              <div className="bg-slate-100 rounded-lg p-12 text-center mb-12">
                <p className="text-slate-700 text-lg mb-4">
                  No use cases available for this combination yet.
                </p>
                <button
                  onClick={() => {
                    setSelectedIndustry(null);
                    setSelectedDepartment(null);
                    setStep("industry");
                  }}
                  className="text-slate-700 font-semibold underline hover:text-slate-900"
                >
                  Try another combination
                </button>
              </div>
            )}

            {/* CTA */}
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-8 text-center">
              <h3 className="text-lg font-bold text-slate-900 mb-2">
                Want to learn more?
              </h3>
              <p className="text-slate-700 mb-4">
                Explore our corporate AI articles and guides to deepen your
                understanding
              </p>
              <a
                href="#"
                className="inline-block px-6 py-3 bg-slate-700 text-white font-semibold rounded-lg hover:bg-slate-800 transition-colors"
              >
                View All Corporate Articles
              </a>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
